package vector

func minInt1ϕ(a, b int1ϕ) int1ϕ {
	if a < b {
		return a
	}
	return b
}

func maxInt1ϕ(a, b int1ϕ) int1ϕ {
	if a > b {
		return a
	}
	return b
}

